decimal sumPercentageDiff = 0;
int validRowCount = 0;
decimal sumFirstWeekMort = 0;
decimal sumTotalCulls = 0;
decimal sumCocks = 0;
decimal sumTotalMort = 0;
decimal sumTotalDepl = 0;
private void xrTableCell15_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
            XRTableCell cell = sender as XRTableCell;

        // Get FABW and StanBodyWeight values
        decimal fabw = Convert.ToDecimal(GetCurrentColumnValue("FABW") ?? 0);
        decimal stanBodyWeight = Convert.ToDecimal(GetCurrentColumnValue("StanBodyWeight") ?? 0);

        // Calculate {@stdVSact} - difference between actual and standard
        decimal stdVSact = 0;
        decimal difference = fabw - stanBodyWeight;

        if (difference != 0)
        {
            stdVSact = difference;
        }

        // Calculate percentage if FABW is not zero
        if (fabw != 0)
        {
            decimal result = (stdVSact / fabw) * 100;
            cell.Text = result.ToString("آ2") ;
        }
        else
        {
            cell.Text = "0.00";
        }
}

private void xrTableCell25_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
           XRTableCell cell = sender as XRTableCell;

        // Get rf_Female_Started value
        decimal rfFemaleStarted = Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);

        // Calculate {@TotalDepl} (TotalMort + TotalCulls + Cocks)
        decimal totalMort = Convert.ToDecimal(GetCurrentColumnValue("TotalMort") ?? 0);
        decimal totalCulls = Convert.ToDecimal(GetCurrentColumnValue("TotalCulls") ?? 0);
        decimal cocks = Convert.ToDecimal(GetCurrentColumnValue("Cocks") ?? 0);
        decimal totalDepl = totalMort + totalCulls + cocks;

        if (rfFemaleStarted != 0)
        {
            // Calculate total depletion percentage
            decimal result = (totalDepl / rfFemaleStarted) * 100;
            cell.Text = result.ToString("N2") ;
        }
        else
        {
            cell.Text = "0.00";
        }
    }
}
// Method to calculate {@stdVSact} for a row
    private decimal CalculateStdVSact(decimal fabw, decimal stanBodyWeight)
    {
        decimal difference = fabw - stanBodyWeight;
        return (difference != 0) ? difference : 0;
    }

    // Method to calculate {@NonZeroBWvsStd} for a row
    private int CalculateNonZeroBWvsStd(decimal stdVSact)
    {
        return (stdVSact != 0) ? 1 : 0;
    }

    // Variables to store sums
    private decimal sumStdVSact = 0;
    private decimal sumNonZeroBWvsStd = 0;

private void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    decimal fabw = Convert.ToDecimal(GetCurrentColumnValue("FABW") ?? 0);
        decimal stanBodyWeight = Convert.ToDecimal(GetCurrentColumnValue("StanBodyWeight") ?? 0);

        // Calculate {@stdVSact} for this row
        decimal stdVSact = CalculateStdVSact(fabw, stanBodyWeight);

        // Calculate {@NonZeroBWvsStd} for this row
        int nonZeroBWvsStd = CalculateNonZeroBWvsStd(stdVSact);

        // Accumulate sums
        sumStdVSact += stdVSact;
        sumNonZeroBWvsStd += nonZeroBWvsStd;

        // Calculate percentage if FABW is not zero
        if (fabw != 0)
        {
            decimal percentageDiff = (stdVSact / fabw) * 100;
            sumPercentageDiff += percentageDiff;
            validRowCount++;
        }

        // Calculate FirstWeekMort for this row (TotalMort + TotalCulls + Cocks)
        decimal totalMort = Convert.ToDecimal(GetCurrentColumnValue("TotalMort") ?? 0);
        decimal totalCulls = Convert.ToDecimal(GetCurrentColumnValue("TotalCulls") ?? 0);
        decimal cocks = Convert.ToDecimal(GetCurrentColumnValue("Cocks") ?? 0);

        decimal firstWeekMort = totalMort + totalCulls + cocks;

        // Add to the running total
        sumFirstWeekMort += firstWeekMort;

                // Add current row's TotalCulls to the running total
        sumTotalCulls += Convert.ToDecimal(GetCurrentColumnValue("TotalCulls") ?? 0);
        sumCocks += Convert.ToDecimal(GetCurrentColumnValue("Cocks") ?? 0);

         sumTotalMort += Convert.ToDecimal(GetCurrentColumnValue("TotalMort") ?? 0);

        decimal totalDepl = totalMort + totalCulls + cocks;

        // Add to running totals
        sumTotalDepl += totalDepl;

}

private void xrTableCell79_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

        if (sumNonZeroBWvsStd != 0)
        {
            decimal result = sumStdVSact / sumNonZeroBWvsStd;
            cell.Text = result.ToString("N2");
        }
        else
        {
            cell.Text = "0.00";
        }
}

private void xrTableCell80_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     XRTableCell cell = sender as XRTableCell;

        if (validRowCount > 0)
        {
            decimal avg = sumPercentageDiff / validRowCount;
            cell.Text = avg.ToString("N2");
        }
        else
        {
            cell.Text = "0.00";
        }
}

private void xrTableCell27_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
      XRTableCell cell = sender as XRTableCell;

    // Get rf_Female_Started and DOA values
    decimal rfFemaleStarted = Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);
    decimal doa = Convert.ToDecimal(GetCurrentColumnValue("DOA") ?? 0);

    if (rfFemaleStarted != 0)
    {
        // Calculate DOA percentage
        decimal result = (doa / rfFemaleStarted) * 100;
        cell.Text = result.ToString("N2");
    }
    else
    {
        cell.Text = "0.00";
    }
}

private void xrTableCell33_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

        // Get rf_Female_Started (you might need to decide which row's value to use)
        // Option A: Use the current row's value
        decimal rfFemaleStarted = Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);

        // Option B: Use the sum of rf_Female_Started across all rows
        // decimal rfFemaleStarted = sumRFemaleStarted; // You'd need to accumulate this too

        if (rfFemaleStarted != 0)
        {
            decimal result = (sumFirstWeekMort / rfFemaleStarted) * 100;
            cell.Text = result.ToString("N2");
        }
        else
        {
            cell.Text = "0.00";
        }
}

private void xrTableCell48_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    XRTableCell cell = sender as XRTableCell;

        // Get {@ChicksPlaced} (rf_Female_Started) - using current row's value
        // You need to decide which row's value to use for the denominator
        decimal chicksPlaced = Convert.ToDecimal(GetCurrentColumnValue("rf_Female_Started") ?? 0);

        if (chicksPlaced != 0)
        {
            decimal result = (sumTotalCulls / chicksPlaced) * 100;
            cell.Text = result.ToString("N2") ;
        }
        else
        {
            cell.Text = "0.00";
        }
}

